optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT ?page ?party ?president ?x
WHERE {
  # Scenario 1: ?x=Concept, ?president=Feature
  {
    SERVICE <http://localhost:8897/sparql/> {
      ?x <http://www.w3.org/2002/07/owl#sameAs> ?president . # ?x:Concept, ?president:Feature
      ?president <http://dbpedia.org/ontology/nationality> <http://dbpedia.org/resource/United_States> .
      ?president <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://dbpedia.org/ontology/President> .
      ?president <http://dbpedia.org/ontology/party> ?party .
      ?x <http://data.nytimes.com/elements/topicPage> ?page .
    }
  }

  UNION

  # Scenario 2: ?x=Drug, ?president=Drug
  {
    SERVICE <http://localhost:8895/sparql/> {
      ?x <http://www.w3.org/2002/07/owl#sameAs> ?president . # ?x:Drug, ?president:Drug
      ?president <http://dbpedia.org/ontology/nationality> <http://dbpedia.org/resource/United_States> .
      ?president <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://dbpedia.org/ontology/President> .
      ?president <http://dbpedia.org/ontology/party> ?party .
      ?x <http://data.nytimes.com/elements/topicPage> ?page .
    }
  }
}
LIMIT 1000
